return [
  { json: { feed: 'Zen Habits', url: 'https://feeds.feedburner.com/zenhabits' } },
  { json: { feed: 'Slow Living Collective', url: 'https://theslowlivingcollective.substack.com/feed' } },
  { json: { feed: 'Google News (EN)', url: 'https://news.google.com/rss/search?q=slow+living&hl=en&gl=US&ceid=US:en' } }
];

function guessFeed(link) {
  const u = String(link);
  if (u.includes('feedburner') || u.includes('zenhabits')) return 'Zen Habits';
  if (u.includes('substack.com')) return 'Slow Living Collective';
  if (u.includes('news.google.com')) return 'Google News (EN)';
  return 'Diğer';
}
const seen = new Set();
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const link = (j.link || j.guid || '').toString();
  if (!link || seen.has(link)) continue;
  seen.add(link);
  out.push({
    json: {
      feed: guessFeed(link),
      title: j.title || '(başlıksız)',
      link,
      pubDate: j.pubDate || j.isoDate || '',
    },
  });
}
return out;

const rows = $input.all().map((i, idx) => {
  const r = i.json;
  const title = String(r.title || '').replace(/</g, '&lt;').replace(/&/g, '&amp;');
  const feed = String(r.feed || '').replace(/</g, '&lt;');
  const link = String(r.link || '').replace(/"/g, '%22');
  return `<tr><td>${idx + 1}</td><td>${feed}</td><td>${title}</td><td><a href=\"${link}\">link</a></td><td>${r.pubDate || ''}</td></tr>`;
}).join('\n');
const html = `<!DOCTYPE html><html><head><meta charset=\"utf-8\"></head><body><h1>Slow living — özet</h1><table border=\"1\" cellpadding=\"6\"><tr><th>#</th><th>Kaynak</th><th>Başlık</th><th>Link</th><th>Tarih</th></tr>${rows}</table></body></html>`;
return [{ json: { html, itemCount: $input.all().length } }];
